import { describe, it } from "vitest";

describe("MHPCO claim-office", () => {
  // Quote — base premiums and processing fee
  it.todo("empty item list yields premium of 5 G (processing fee only)");
  it.todo("quote for a single plain sword (steel, ench 3, not cursed, 0 years, first contract) yields 100 + 10 first-insurance + 5 fee = 115 G");
  it.todo("quote for a single plain amulet (silver, ench 2, not cursed, 0 years, first contract) yields 60 + 6 + 5 = 71 G (rounded up to 72? — check rounding)");
  it.todo("quote for a plain staff yields 80 G base premium component");
  it.todo("quote for a plain potion yields 40 G base premium component");

  // Components
  it.todo("quote for 2 runes yields 50 G base premium (no block)");
  it.todo("quote for 3 runes yields 60 G base premium (block applies)");
  it.todo("quote for 4 runes yields 100 G base premium (no block — block requires exactly 3)");
  it.todo("quote for 7 runes yields 175 G base premium (3 + 4 = block of 3 plus 4 singles? actually 7×25 = 175)");
  it.todo("quote for 2 runes + 1 moonstone yields 75 G base premium (no block: different types)");
  it.todo("quote for 3 runes + 3 moonstones yields 120 G base premium (two separate blocks)");

  // Item-specific modifiers
  it.todo("cursed sword adds 50% surcharge to its base premium");
  it.todo("sword with enchantment exactly 5 adds 30% high-enchantment surcharge");
  it.todo("sword with enchantment 4 does not add high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 adds both surcharges");

  // Policy-wide modifiers
  it.todo("customer with exactly 2 years receives 20% loyalty discount on policy base");
  it.todo("first item in a quote receives 10% first-insurance surcharge per item");
  it.todo("second and later contracts in a scenario receive a 15% follow-up-contract discount on policy base");

  // Integration: newcomer with cursed sword example
  it.todo("newcomer (0 years) with cursed sword (steel ench 3) → premium 165 G");
  it.todo("long-standing customer's 2nd contract: cursed sword (ench 7), 3 years → premium 160 G");

  // Multi-item modifier scope
  it.todo("policy with cursed sword + plain amulet: cursed surcharge applies only to sword base; loyalty/first/follow-up apply to policy base");

  // Rounding
  it.todo("premium rounded up (in MHPCO favor): 197.5 → 198");
  it.todo("payout rounded down (in MHPCO favor): 350.5 → 350");

  // Claim — basic payout
  it.todo("regular sword (steel, ench 3) damage 500 → payout 400 (deductible 100)");
  it.todo("damage to a rune (insurance 250) damage 200 → payout 100 (deductible 100)");

  // Claim — special clauses
  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon: full, minus deductible)");
  it.todo("steel sword, ench 9, damage 1000 → payout 400 (high-ench: 50% then deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (50% rule wins over dragon)");
  it.todo("dragon sword, ench exactly 8, damage 1000 → payout 400 (high-ench clause applies at 8)");

  // Claim — deductible per damage event
  it.todo("dragon attack damages sword(500) and amulet(300) → payout 600 (100 deductible per item)");

  // Claim — multiple items same type
  it.todo("policy covers two swords; damage to both → each is separate damage with own deductible");
  it.todo("damages contains more entries of a type than insured → CLI exits non-zero, claim rejected");

  // Cap
  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword: cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block): insurance sum 1750 G; block discount does not reduce cap");
  it.todo("two successive claims of 1500 G against sword (cap 2000): first 1400, then 600, remainingCap 0");

  // Validation / errors
  it.todo("quote with unknown item type exits non-zero with stderr message; no results");
  it.todo("claim references item not in policy → exits non-zero with stderr");
  it.todo("claim contains damage with negative amount → exits non-zero with stderr");

  // CLI integration
  it.todo("CLI reads scenario JSON from stdin and writes {results: [...]} to stdout");
});

