type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const PROCESSING_FEE = 5;

const basePremiumOf = (item: Item): number => {
  if (item.type === "sword") return 100;
  if (item.type === "amulet") return 60;
  return 0;
};

const quotePremium = (step: Step): number => {
  const itemPremiums = step.items.map((item) => {
    const base = basePremiumOf(item);
    return base + base * 0.1; // first-insurance surcharge per item
  });
  const total = itemPremiums.reduce((a, b) => a + b, 0);
  return Math.ceil(total + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => ({
  results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
});

