type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;

const COMPONENT_TYPES = new Set(["rune"]);
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const isComponentBlock = (items: Item[]): boolean =>
  items.length === BLOCK_SIZE &&
  items.every(isComponent) &&
  items.every((item) => item.type === items[0].type);

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremiumOf(item), 0);

const basePremiumForItems = (items: Item[]): number =>
  isComponentBlock(items) ? BLOCK_BASE_PREMIUM : sumBasePremiums(items);

const quotePremium = (step: Step): number => {
  const base = basePremiumForItems(step.items);
  const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => ({
  results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
});

