import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO claim-office", () => {
  // Quote — base premiums and processing fee
  it("empty item list yields premium of 5 G (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("quote for a single plain sword yields 100 + 10 first-insurance + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote for a single plain amulet yields 60 + 6 + 5 = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote for a plain staff yields 80 + 8 + 5 = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "wood", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("quote for a plain potion yields 40 + 4 + 5 = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // Components
  it("quote for 2 runes yields 50 G base + 5 first-insurance + 5 fee = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("quote for 3 runes yields block 60 + 6 + 5 = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote for 4 runes yields 100 + 10 + 5 = 115 G (no block — block requires exactly 3)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote for 7 runes yields base 175 → premium 198 G (7×25, no block; rounded up)", () => {
    const items = Array.from({ length: 7 }, () => ({ type: "rune" }));
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items }],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("quote for 2 runes + 1 moonstone yields base 75 → premium 88 G (no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("quote for 3 runes + 3 moonstones yields base 120 → premium 137 G (two blocks)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // Item-specific modifiers
  it("newcomer with cursed sword (steel ench 3) → premium 165 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("sword with enchantment exactly 5 adds 30% high-enchantment surcharge → premium 145 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("sword with enchantment 4 does not add high-enchantment surcharge → premium 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("cursed sword with enchantment 5 adds both surcharges → premium 195 G", () => {
    // 100 base + 50 curse + 30 high-ench + 10 first-insurance + 5 fee = 195
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 195 }] });
  });

  // Policy-wide modifiers
  it("customer with exactly 2 years receives 20% loyalty discount → premium 95 G", () => {
    // 100 base - 20 loyalty + 10 first-insurance + 5 fee = 95
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it.todo("first item in a quote receives 10% first-insurance surcharge per item");
  it.todo("second and later contracts in a scenario receive a 15% follow-up-contract discount on policy base");

  // Integration: newcomer with cursed sword example
  it.todo("newcomer (0 years) with cursed sword (steel ench 3) → premium 165 G");
  it.todo("long-standing customer's 2nd contract: cursed sword (ench 7), 3 years → premium 160 G");

  // Multi-item modifier scope
  it.todo("policy with cursed sword + plain amulet: cursed surcharge applies only to sword base; loyalty/first/follow-up apply to policy base");

  // Rounding
  it.todo("premium rounded up (in MHPCO favor): 197.5 → 198");
  it.todo("payout rounded down (in MHPCO favor): 350.5 → 350");

  // Claim — basic payout
  it.todo("regular sword (steel, ench 3) damage 500 → payout 400 (deductible 100)");
  it.todo("damage to a rune (insurance 250) damage 200 → payout 100 (deductible 100)");

  // Claim — special clauses
  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon: full, minus deductible)");
  it.todo("steel sword, ench 9, damage 1000 → payout 400 (high-ench: 50% then deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (50% rule wins over dragon)");
  it.todo("dragon sword, ench exactly 8, damage 1000 → payout 400 (high-ench clause applies at 8)");

  // Claim — deductible per damage event
  it.todo("dragon attack damages sword(500) and amulet(300) → payout 600 (100 deductible per item)");

  // Claim — multiple items same type
  it.todo("policy covers two swords; damage to both → each is separate damage with own deductible");
  it.todo("damages contains more entries of a type than insured → CLI exits non-zero, claim rejected");

  // Cap
  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword: cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block): insurance sum 1750 G; block discount does not reduce cap");
  it.todo("two successive claims of 1500 G against sword (cap 2000): first 1400, then 600, remainingCap 0");

  // Validation / errors
  it.todo("quote with unknown item type exits non-zero with stderr message; no results");
  it.todo("claim references item not in policy → exits non-zero with stderr");
  it.todo("claim contains damage with negative amount → exits non-zero with stderr");

  // CLI integration
  it.todo("CLI reads scenario JSON from stdin and writes {results: [...]} to stdout");
});

